WITH product_assets AS (
  SELECT *
  FROM jsonb_to_recordset($asset_json$[{"sku":"1003","longDescription":"Kofer Travel Mate S 57 cm – savršen spoj praktičnosti i elegancije za bezbrižna putovanja\nPutujte sa stilom uz ovaj luksuzni kofer, dizajniran za maksimalnu funkcionalnost i organizaciju. Kofer je izrađen od čvrstog i laganog materijala, sa sofisticiranim geometrijskim uzorkom koji odaje moderan i profesionalan izgled.\nBez obzira na to da li putujete poslovno ili turistički, ovaj kofer pruža savršen balans između elegancije, funkcionalnosti i trajnosti. Iskoristite vrhunsku mobilnost i zaštitu, i putujte bez brige!\n• Dimenzije: 57x36x22cm - savršeno se uklapa za kratkotrajna putovanja i kabinske dimenzije avionskog prevoza.\n• Materijal i izgled: Površina kofera ima teksturisan uzorak dijagonalnih linija koje podsećaju na strelice, pružajući moderan i sofisticiran izgled. Napravljen je od ABS plastike koja pruža otpornost na udarce i ogrebotine, što pomaže u zaštiti sadržaja kofera.\n• Točkovi i mobilnost: Kofer je opremljen sa četiri spinner točka koji omogućavaju lako manevrisanje 360º, olakšavajući kretanje kroz aerodrome, ulice ili bilo koje drugo okruženje.\n• Sigurnosne funkcije: Ima ugrađene brave za dodatnu bezbednost pri međunarodnim putovanjima.\n• Ručke: Ima teleskopsku metalnu ručku koja se lako podešava u skladu sa vašim potrebama. Osim toga, na bočnim stranama su crne plastične ručke za jednostavno nošenje.\n• Prostor: Unutrašnjost kofera je prostrana, idealna za pakovanje garderobe i drugih putnih potrepština.\n• Lagan dizajn: Dizajniran je da bude što lakši, olakšavajući nošenje i transport, čak i kada je potpuno napunjen.\n• Elegantna estetika: Sveden dizajn i neutralna boja čine ga pogodnim i za poslovna i za rekreativna putovanja."},{"sku":"1004","longDescription":"Kofer Travel Mate M 67 cm – savršen spoj praktičnosti i elegancije za bezbrižna putovanja\nPutujte sa stilom uz ovaj luksuzni kofer, dizajniran za maksimalnu funkcionalnost i organizaciju. Kofer je izrađen od čvr